// ============================================================
// CONFIGURACIÓN DE REPROCESO
// Completar antes de ejecutar este workflow
// ============================================================

// PASO 1: Pegar aquí los códigos SAP faltantes detectados por el WF1
const CODIGOS_SAP_A_REPROCESAR = [
  '2600464615',  // <-- Reemplazar con los códigos reales
  '2600464220'   // <-- Agregar/quitar líneas según sea necesario
];

// PASO 2: Definir el entorno
const ENTORNO = 'PRODUCCION'; // 'PRODUCCION' (→ .PFA) o 'TEST' (→ .TFA)

// PASO 3: Si conoce el nombre exacto del archivo, completar aquí.
// Si deja vacío, el workflow buscará el archivo más reciente en BackUpSeparador.
const NOMBRE_ARCHIVO_ESPECIFICO = ''; // Ej: 'facturas_2024-01-15.PFA' o dejar ''

// ============================================================

if (!CODIGOS_SAP_A_REPROCESAR || CODIGOS_SAP_A_REPROCESAR.length === 0) {
  throw new Error('Debe especificar al menos un código SAP para reprocesar.');
}

const extension = ENTORNO === 'PRODUCCION' ? '.PFA' : '.TFA';

return [{
  json: {
    codigosSAPObjetivo: CODIGOS_SAP_A_REPROCESAR,
    cantidadObjetivo:   CODIGOS_SAP_A_REPROCESAR.length,
    entorno:            ENTORNO,
    extension:          extension,
    archivoEspecifico:  NOMBRE_ARCHIVO_ESPECIFICO,
    fechaReproceso:     new Date().toISOString().split('T')[0],
    timestamp:          new Date().toISOString()
  }
}];

// Selecciona el archivo fuente para extraer los XMLs de reproceso
const config     = $('Configurar Reproceso').first().json;
const archivos   = $input.all();
const extension  = config.extension;

let archivoElegido;

if (config.archivoEspecifico) {
  // Buscar el archivo exacto si fue especificado
  const encontrado = archivos.find(f => f.json.name === config.archivoEspecifico);
  if (!encontrado) {
    throw new Error(`Archivo específico no encontrado: ${config.archivoEspecifico}`);
  }
  archivoElegido = encontrado.json;
} else {
  // Tomar el más reciente con la extensión correcta
  const filtrados = archivos
    .filter(f => f.json.name && f.json.name.toUpperCase().endsWith(extension.toUpperCase()))
    .sort((a, b) => new Date(b.json.modifyTime || 0) - new Date(a.json.modifyTime || 0));

  if (filtrados.length === 0) {
    throw new Error(`No se encontraron archivos ${extension} en BackUpSeparador.`);
  }
  archivoElegido = filtrados[0].json;
}

return [{
  json: {
    ...config,
    fileName:   archivoElegido.name,
    filePath:   `/Directorios/FTP/1028501021/BackUpSeparador/${archivoElegido.name}`
  }
}];

// Extrae del archivo combinado sólo los comprobantes con los códigos SAP objetivo
// y genera un item por cada XML individual listo para subir al FTP

const config    = $('Seleccionar Archivo para Reproceso').first().json;
const item      = $input.first();
const binaryData = item.binary?.data;

if (!binaryData) {
  throw new Error('No se recibió el contenido del archivo XML fuente.');
}

const xmlContent = Buffer.from(binaryData.data, 'base64').toString('utf-8');
const codigosObjetivo = config.codigosSAPObjetivo.map(c => String(c));

// ============================================================
// EXTRACCIÓN DE COMPROBANTES INDIVIDUALES
// Asume estructura: <Comprobante>...</Comprobante> por documento
// Ajustar el tag según la estructura real del XML del cliente
// ============================================================
const TAG_COMPROBANTE = 'Comprobante'; // <-- Verificar con estructura real

const regexComprobante = new RegExp(
  `<${TAG_COMPROBANTE}[\\s\\S]*?<\/${TAG_COMPROBANTE}>`,
  'g'
);

const xmlHeader = '<?xml version="1.0" encoding="UTF-8"?>';
const resultados = [];
let match;

while ((match = regexComprobante.exec(xmlContent)) !== null) {
  const bloqueXML = match[0];

  // Verificar si este bloque contiene alguno de los códigos objetivo
  const textoLibre1Match = bloqueXML.match(/<TextoLibre1>([^<]+)<\/TextoLibre1>/);
  if (!textoLibre1Match) continue;

  const codigoSAP = textoLibre1Match[1].trim();
  if (!codigosObjetivo.includes(codigoSAP)) continue;

  // Construir XML individual con cabecera y el tag raíz
  // NOTA: NO numerar el archivo (la interfaz numera automáticamente)
  // NOTA: NO subir dentro de una contingencia
  const xmlIndividual = `${xmlHeader}\n<Comprobantes>\n${bloqueXML}\n</Comprobantes>`;
  const fileName      = `${codigoSAP}${config.extension}`;

  resultados.push({
    json: {
      codigoSAP,
      fileName,
      destinoFTP:   `/Directorios/FTP/1028501021/${fileName}`,
      entorno:      config.entorno,
      fechaReproceso: config.fechaReproceso
    },
    binary: {
      data: {
        data:     Buffer.from(xmlIndividual, 'utf-8').toString('base64'),
        mimeType: 'application/xml',
        fileName: fileName
      }
    }
  });
}

if (resultados.length === 0) {
  throw new Error(
    `No se encontraron comprobantes para los códigos: ${codigosObjetivo.join(', ')}. ` +
    `Verificar el tag <${TAG_COMPROBANTE}> en el archivo XML.`
  );
}

const codigosNoEncontrados = codigosObjetivo.filter(
  c => !resultados.some(r => r.json.codigoSAP === c)
);

if (codigosNoEncontrados.length > 0) {
  console.warn('Códigos no encontrados en el XML:', codigosNoEncontrados.join(', '));
}

return resultados;

// Consolida todos los archivos subidos en un único resumen
const items = $input.all();
const config = $('Configurar Reproceso').first().json;

const archivosSubidos = items.map(i => i.json.fileName);
const codigosSubidos  = items.map(i => i.json.codigoSAP);
const codigosFaltantesAun = config.codigosSAPObjetivo.filter(
  c => !codigosSubidos.includes(c)
);

return [{
  json: {
    reprocesado:         codigosSubidos.length > 0,
    archivosSubidos,
    codigosSubidos,
    codigosFaltantesAun,
    cantidadSubidos:     codigosSubidos.length,
    cantidadFaltantesAun: codigosFaltantesAun.length,
    entorno:             config.entorno,
    fechaReproceso:      config.fechaReproceso,
    mensaje:             codigosFaltantesAun.length === 0
      ? 'Todos los archivos de reproceso fueron subidos exitosamente.'
      : `${codigosSubidos.length} archivos subidos. ${codigosFaltantesAun.length} códigos no encontrados en el XML fuente.`
  }
}];
